typedef enum SDL_JoystickConnectionState
{
 SDL_JOYSTICK_CONNECTION_INVALID = -1, /**< تعاد هذه القيمة عندما تكون INVALID هي الحالة الفعلية في التعداد SDL_JoystickConnectionState، وعند ظهورها يعتمد SDL أو التطبيق هذا المسار في المعالجة اللاحقة. */
 SDL_JOYSTICK_CONNECTION_UNKNOWN, /**< تعاد هذه القيمة عندما تكون UNKNOWN هي الحالة الفعلية في التعداد SDL_JoystickConnectionState، وعند ظهورها يعتمد SDL أو التطبيق هذا المسار في المعالجة اللاحقة. */
 SDL_JOYSTICK_CONNECTION_WIRED, /**< تعاد هذه القيمة عندما تكون WIRED هي الحالة الفعلية في التعداد SDL_JoystickConnectionState، وعند ظهورها يعتمد SDL أو التطبيق هذا المسار في المعالجة اللاحقة. */
 SDL_JOYSTICK_CONNECTION_WIRELESS /**< تعاد هذه القيمة عندما تكون WIRELESS هي الحالة الفعلية في التعداد SDL_JoystickConnectionState، وعند ظهورها يعتمد SDL أو التطبيق هذا المسار في المعالجة اللاحقة. */
} SDL_JoystickConnectionState;
